export const COUNTRIES = [
  { code: "ALL", label: "🌎 Todos" },
  { code: "AR", label: "🇦🇷 Argentina" },
  { code: "MX", label: "🇲🇽 México" },
  { code: "ES", label: "🇪🇸 España" },
  { code: "LATAM", label: "🌎 LATAM" },
];

export const LATAM_COUNTRIES = ["AR","MX","CO","PE","CL","VE","UY","SV","PR","DO","GT","HN","CR","PA","CU","NI","BO","PY","EC","FR","NO"];

export const REDUCED_WEIGHT_COUNTRIES = ["AR","MX"];

export function getStreamersByCountry(country) {
  if (country === "ALL") return STREAMERS;
  if (country === "LATAM") return STREAMERS.filter(s => s.country !== "ES");
  return STREAMERS.filter(s => s.country === country);
}

export function searchStreamers(query, country = "ALL") {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  let pool = getStreamersByCountry(country);
  return pool.filter(s => {
    const fields = [s.name, s.display_name, s.twitch, s.kick, ...s.aliases].map(f => (f || "").toLowerCase());
    return fields.some(f => f.includes(q));
  });
}

export function getDailyStreamer(country = "ALL", gameOffset = 0) {
  const pool = getStreamersByCountry(country);
  const today = new Date();
  const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate();
  return pool[(seed + gameOffset) % pool.length];
}

export function getDailyStreamerNoRepeat(country = "ALL", gameKey = "classic", offset = 0, filter = null) {
  let pool = getStreamersByCountry(country);
  if (filter) pool = pool.filter(filter);
  const today = new Date();
  const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate();
  let history = [];
  if (typeof window !== "undefined") {
    try { history = JSON.parse(localStorage.getItem(`history_${gameKey}_${country}`) || "[]"); } catch { history = []; }
  }
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - 30);
  const recentIds = history.filter(h => new Date(h.date) > cutoff).map(h => h.id);
  const available = pool.filter(s => !recentIds.includes(s.id));
  const finalPool = available.length > 0 ? available : pool;

  // Sistema de pesos: en LATAM, AR y MX tienen 40% menos probabilidad
  let weightedPool = finalPool;
  if (country === "LATAM") {
    weightedPool = [];
    finalPool.forEach(s => {
      // AR y MX se agregan 6 veces en vez de 10 (40% menos)
      const weight = REDUCED_WEIGHT_COUNTRIES.includes(s.country) ? 6 : 10;
      for (let i = 0; i < weight; i++) weightedPool.push(s);
    });
  }

  const streamer = weightedPool[(seed + offset) % weightedPool.length];

  if (typeof window !== "undefined") {
    const todayStr = today.toISOString().split("T")[0];
    const alreadyToday = history.some(h => h.date === todayStr && h.game === gameKey);
    if (!alreadyToday) {
      history.push({ id: streamer.id, date: todayStr, game: gameKey });
      try { localStorage.setItem(`history_${gameKey}_${country}`, JSON.stringify(history)); } catch {}
    }
  }
  return streamer;
}
export function getYesterdayStreamer(country = "ALL", gameKey = "classic", offset = 0, filter = null) {
  let pool = getStreamersByCountry(country);
  if (filter) pool = pool.filter(filter);
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const seed = yesterday.getFullYear() * 10000 + (yesterday.getMonth() + 1) * 100 + yesterday.getDate();

  if (country === "LATAM") {
    const weighted = [];
    pool.forEach(s => {
      const weight = ["AR","MX"].includes(s.country) ? 6 : 10;
      for (let i = 0; i < weight; i++) weighted.push(s);
    });
    return weighted[(seed + offset) % weighted.length];
  }

  return pool[(seed + offset) % pool.length];
}